import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.BZO4qERu.js";const r=JSON.parse('{"title":"Lark CLI、云文档、表单、Doctor 与交互卡片 JSON 注入","description":"","frontmatter":{},"headers":[],"relativePath":"guide/cloud-docs-and-cards.md","filePath":"guide/cloud-docs-and-cards.md","lastUpdated":1780517912000}'),n={name:"guide/cloud-docs-and-cards.md"};function l(p,s,o,d,c,h){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="lark-cli、云文档、表单、doctor-与交互卡片-json-注入" tabindex="-1">Lark CLI、云文档、表单、Doctor 与交互卡片 JSON 注入 <a class="header-anchor" href="#lark-cli、云文档、表单、doctor-与交互卡片-json-注入" aria-label="Permalink to &quot;Lark CLI、云文档、表单、Doctor 与交互卡片 JSON 注入&quot;">​</a></h1><p>重命名这一节，叫做飞书功能，另外什么本机依赖这些东西就不要讲了</p><h2 id="lark-cli-与云文档评论" tabindex="-1">lark-cli 与云文档评论 <a class="header-anchor" href="#lark-cli-与云文档评论" aria-label="Permalink to &quot;lark-cli 与云文档评论&quot;">​</a></h2><p>本阶段已在 Node.js 24 环境下安装并验证 <code>@larksuite/cli</code>，本机 <code>lark-cli --version</code> 为 <code>1.0.45</code>。<code>@larksuite/cli</code> 也已加入项目依赖管理：<code>package.json</code> 依赖为 <code>@larksuite/cli: ^1.0.45</code>，<code>package-lock.json</code> 锁定了 <code>node_modules/@larksuite/cli</code> 及其 <code>lark-cli</code> bin。<code>lark-cli docs --help</code> 显示文档能力包含 <code>docs +fetch</code> 与 <code>docs +update</code>，并提示 Docs v2 应显式使用 <code>--api-version v2</code>。</p><p>Codex-to-IM 的云文档入口仍由飞书事件 <code>drive.notice.comment_add_v1</code> 触发。默认模式下，用户需要在云文档评论里 @ 机器人；Bridge 会用 <code>doc:&lt;file_type&gt;:&lt;file_token&gt;</code> 作为聊天 ID 建立或复用评论回复会话，把评论 file token、file type、comment id、reply id、引用内容和用户问题拼成一次普通 runtime turn。默认模式建立后，同一文档后续评论可以作为这条云文档评论会话的后续消息处理；最终回复通过 Drive 评论 reply 接口写回触发本轮输入的同一个评论线程。</p><p>云文档评论里 @ 机器人后发送 <code>/new [群名] [目录]</code> 会启用显式 doc-as-chat 模式。Bridge 会创建飞书群聊，把这份云文档映射到该群聊，并在群聊里承载后续普通 IM 对话。新模式建立后，云文档评论不再接入 bot 对话；如果用户继续在云文档评论里发消息，Bridge 只回复提示用户去已创建的群聊聊天。</p><p>未建立默认模式或新模式的文档评论仍必须 @ 机器人或在评论富文本内容里提及机器人，避免 bridge 把无关文档评论当成聊天消息。机器人自己写出的评论会被忽略，避免回复回环。</p><p>为了让 agent 能真的读取或修改文档正文，云文档 prompt 现在会告诉模型直接调用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lark-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +fetch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --api-version</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --as</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --doc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">file_toke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lark-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --api-version</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --as</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --doc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">file_toke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> append</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --markdown</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;内容&gt;&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lark-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --api-version</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --as</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --doc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">file_toke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> replace_range</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --selection-by-title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;标题&gt;&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --markdown</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;内容&gt;&#39;</span></span></code></pre></div><p>如果 <code>lark-cli</code> 或机器人权限不可用，模型应在云文档评论里明确说明需要补 CLI 绑定或 Drive 权限，而不是假装已经读取了文档正文。</p><p>云文档评论还会在 turn 开始前给目标 reply 添加 <code>Typing</code> reaction，回复完成后在 <code>sendCloudDocumentReply()</code> 的 <code>finally</code> 中删除。使用的接口是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /open-apis/drive/v2/files/{fileToken}/comments/reaction?file_type={fileType}</span></span>
<span class="line"><span>body: { &quot;action&quot;: &quot;add|delete&quot;, &quot;reply_id&quot;: &quot;...&quot;, &quot;reaction_type&quot;: &quot;Typing&quot; }</span></span></code></pre></div><h2 id="cti-ask-表单" tabindex="-1"><code>&lt;cti-ask&gt;</code> 表单 <a class="header-anchor" href="#cti-ask-表单" aria-label="Permalink to &quot;\`&lt;cti-ask&gt;\` 表单&quot;">​</a></h2><p>模型现在可以让 Bridge 生成一个飞书 CardKit 2.0 表单，而不只是按钮卡片。协议示例：</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cti-ask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{&quot;question&quot;:&quot;请选择发布策略&quot;,&quot;options&quot;:[&quot;灰度&quot;,&quot;全量&quot;],&quot;input&quot;:{&quot;label&quot;:&quot;补充说明&quot;,&quot;placeholder&quot;:&quot;可留空&quot;},&quot;submitText&quot;:&quot;提交&quot;,&quot;allowTextReply&quot;:true}&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">cti-ask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>渲染规则：</p><ul><li><code>options</code> 会渲染为一个 <code>select_static</code>。</li><li><code>input</code> 会渲染为可为空的文本框。</li><li>提交按钮使用 <code>form_action_type: &quot;submit&quot;</code>。</li><li>CardKit 2.0 提交值会出现在 raw event 的 <code>action.form_value</code>，key 是控件 <code>name</code>。因此表单控件使用固定 name：<code>cti_choice</code> 与 <code>cti_input</code>。</li></ul><p>用户提交后，Bridge 会把回调转成同一会话里的下一条消息：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[用户回答了问题卡片]</span></span>
<span class="line"><span>问题：请选择发布策略</span></span>
<span class="line"><span>回答：选择：灰度</span></span>
<span class="line"><span>补充：可以先给 10% 用户</span></span></code></pre></div><p>如果补充输入框为空，会显式回传 <code>补充：（空）</code>，让模型知道用户是自由提交而不是消息丢失。</p><h2 id="doctor-时间参数" tabindex="-1"><code>/doctor</code> 时间参数 <a class="header-anchor" href="#doctor-时间参数" aria-label="Permalink to &quot;\`/sites/codelark/doctor\` 时间参数&quot;">​</a></h2><p><code>/doctor</code> 会读取 <code>~/.codex-to-im/logs/bridge.log</code>，把日志片段和用户描述交给当前 Codex 会话分析。新增的第一个参数是时间范围：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/doctor</span></span>
<span class="line"><span>/doctor 10m 飞书卡片点击没反应</span></span>
<span class="line"><span>/doctor 2h bridge 重启后无法连接</span></span>
<span class="line"><span>/doctor 2026-06-02T01:00:00+08:00 云文档评论没有回复</span></span></code></pre></div><p>时间参数支持：</p><ul><li>相对时长：<code>10s</code>、<code>10m</code>、<code>2h</code>、<code>1d</code>。</li><li>可被 <code>Date.parse()</code> 解析的时间戳。</li><li>不传时间时默认最近 30 分钟。</li></ul><p>Bridge 会先在聊天里发一条 notice，说明读取了哪个时间窗口和多少行日志，然后把日志诊断 prompt 投递给当前会话。</p><h2 id="交互卡片原始-json-注入" tabindex="-1">交互卡片原始 JSON 注入 <a class="header-anchor" href="#交互卡片原始-json-注入" aria-label="Permalink to &quot;交互卡片原始 JSON 注入&quot;">​</a></h2><p>“交互卡片原始 JSON 注入”指的是：当用户发送或引用一张飞书交互卡片时，不只把 SDK 抽出来的可见文字发给模型，还把卡片真实 JSON 包在一个专用块里发给模型：</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">interactive_card</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ &quot;schema&quot;: &quot;2.0&quot;, &quot;header&quot;: { ... }, &quot;body&quot;: { ... } }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">interactive_card</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>它解决的是 SDK 文本扁平化丢信息的问题。CardKit 2.0 事件里经常同时带有一个旧客户端 fallback <code>elements</code> 和真正的 <code>user_dsl</code>；如果只读 fallback，模型可能只看到“请升级至最新版本客户端”。原始 JSON 注入会优先把真实 <code>user_dsl</code> 或 schema 2.0 DSL 给模型。</p><p>这和 <code>&lt;cti-ask&gt;</code> 表单不是同一条链路：</p><ul><li><code>&lt;cti-ask&gt;</code> 是模型主动要求 Bridge 发一张受控问题卡片。</li><li><code>&lt;interactive_card&gt;</code> 是用户侧已有卡片进入模型上下文，帮助模型理解那张卡的结构、按钮、字段和值。</li></ul><p>当前实现入口在 Feishu adapter：</p><ul><li>用户直接发送 <code>interactive</code> 消息时，Bridge 会把该消息作为普通用户输入转给模型，并附上 <code>&lt;interactive_card&gt;</code>。</li><li>用户引用一条消息作出回答时，Feishu receive event 的 <code>message.parent_id</code> 会被用于调用 <code>im.message.get</code> 读取被引用消息；如果被引用消息是 <code>interactive</code>，Bridge 会优先抽取 <code>data.user_dsl</code>，否则保留可解析的卡片 JSON，再放进专用的 <code>&lt;quoted_message&gt;</code> 引用块附加到模型 prompt。</li></ul><p>用户引用一张交互卡片并回复“按这个窗口发”时，模型实际收到的 prompt 形态是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>按这个窗口发</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;quoted_message platform=&quot;feishu&quot; message_id=&quot;card-parent-1&quot; message_type=&quot;interactive&quot;&gt;</span></span>
<span class="line"><span>&lt;interactive_card&gt;</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;schema&quot;: &quot;2.0&quot;,</span></span>
<span class="line"><span>  &quot;body&quot;: {</span></span>
<span class="line"><span>    &quot;elements&quot;: [</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        &quot;tag&quot;: &quot;markdown&quot;,</span></span>
<span class="line"><span>        &quot;content&quot;: &quot;发布窗口：今晚 22:00&quot;</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>&lt;/interactive_card&gt;</span></span>
<span class="line"><span>&lt;/quoted_message&gt;</span></span></code></pre></div><p>这里的第一段是用户本次发送的正文；空行后的 <code>&lt;quoted_message&gt;</code> 明确告诉模型“下面是被引用消息，不是用户新输入”。这个上下文只在普通模型输入阶段追加，不参与 <code>/doctor</code>、<code>/t</code>、<code>/stop</code> 等 Bridge 命令解析。</p>`,37)])])}const u=a(n,[["render",l]]);export{r as __pageData,u as default};
